SELECT tbp.bbs_pst_oid, tbp.bbs_oid, tbp.user_oid, tbp.wrtr_nm, tbp.wrtr_pswd, tbp.bbs_pst_ttl, tbp.bbs_pst_cn, tbp.bbs_pst_cn_txt, tbp.ctgry, tbp.ntc_yn, tbp.prvt_pst_yn, tbp.inq_cnt, tbp.like_cnt, tbp.cmnt_cnt, tbp.atch_cnt, IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') AS upend_fix_yn, tbp.bgng_dt, tbp.end_dt, tbp.stts, tbp.ddln_dt, tbp.up_bbs_pst_oid, tbp.reply_lv, tbp.reply_seq, tbp.open_yn, tbp.rcrt_type, tbp.del_yn, tbp.del_dt, tbp.reg_id, tbp.reg_dt, tbp.mdfcn_id, tbp.mdfcn_dt, CASE WHEN tbp.ddln_dt IS NOT NULL AND DATE(tbp.ddln_dt) < DATE(NOW()) THEN '마감' WHEN DATE(tbp.reg_dt) > DATE(NOW()) THEN '예정' WHEN tbp.ddln_dt IS NULL THEN '' ELSE '진행중' END AS stts_nm FROM ${schema}.bbs_pst tbp
AND tbp.del_yn = #{delYn}
AND tbp.del_yn = 'N'
AND tbp.open_yn = #{openYn}
AND tbp.open_yn = 'Y' AND ( tbp.bgng_dt IS NULL OR tbp.bgng_dt <= CURDATE() )
AND tbp.open_yn = 'Y' AND ( tbp.bgng_dt IS NULL OR tbp.bgng_dt <= CURDATE() )
AND ( tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE() )
AND tbp.reg_dt >= #{regStartDt}
AND tbp.reg_dt < DATE_ADD(#{regEndDt}, INTERVAL 1 DAY)
AND tbp.bbs_oid = #{bbsOid}
AND tbp.ctgry = #{ctgry}
AND
MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE)
MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE)
(MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE) OR MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE))
ORDER BY IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') DESC, tbp.bbs_pst_oid DESC

SELECT tbp.bbs_pst_oid, tbp.bbs_oid, tbp.user_oid, tbp.wrtr_nm, tbp.bbs_pst_ttl, tbp.bbs_pst_cn_txt, tbp.ctgry, tbp.ntc_yn, tbp.prvt_pst_yn, tbp.inq_cnt, tbp.like_cnt, tbp.cmnt_cnt, tbp.atch_cnt, IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') AS upend_fix_yn, tbp.bgng_dt, tbp.end_dt, tbp.stts, tbp.ddln_dt, tbp.open_yn, tbp.del_yn, tbp.reg_id, tbp.reg_dt, tbp.mdfcn_id, tbp.mdfcn_dt, CASE WHEN tbp.ddln_dt IS NOT NULL AND DATE(tbp.ddln_dt) < DATE(NOW()) THEN '마감' WHEN DATE(tbp.reg_dt) > DATE(NOW()) THEN '예정' WHEN tbp.ddln_dt IS NULL THEN '' ELSE '진행중' END AS stts_nm FROM ${schema}.bbs_pst tbp WHERE tbp.del_yn = 'N' AND tbp.open_yn = 'Y' AND tbp.bbs_oid = #{bbsOid}
AND tbp.ctgry = #{ctgry}
ORDER BY IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') DESC, tbp.bbs_pst_oid DESC

SELECT tf.file_oid, tf.tbl_nm, tf.tbl_oid, tf.orgnl_file_nm, tf.strg_file_nm, tf.strg_file_path, tf.strg_file_cpct, tf.file_type_nm, tf.file_type, tf.thmb_yn, tf.atch_file_seq, tf.use_yn, tf.reg_id, tf.reg_dt, tf.mdfcn_id, tf.mdfcn_dt FROM ${schema}.file tf WHERE tf.tbl_oid IN
#{bbsPstOid}
AND tf.tbl_nm = 'bbs_pst' AND tf.use_yn = 'Y' AND tf.file_type = 'ATTACHMENT' ORDER BY tf.tbl_oid, tf.atch_file_seq ASC

SELECT tbp.bbs_pst_oid, tbp.bbs_oid, tbp.user_oid, tbp.wrtr_nm, tbp.wrtr_pswd, tbp.bbs_pst_ttl, tbp.bbs_pst_cn, tbp.bbs_pst_cn_txt, tbp.ctgry, tbp.ntc_yn, tbp.prvt_pst_yn, tbp.inq_cnt, tbp.like_cnt, tbp.cmnt_cnt, tbp.atch_cnt, tbp.stts, tc.cd_nm AS qna_status, tbp.ddln_dt, tbp.up_bbs_pst_oid, tbp.reply_lv, tbp.reply_seq, tbp.del_yn, tbp.del_dt, tbp.reg_id, tbp.reg_dt, tbp.mdfcn_id, tbp.mdfcn_dt, CASE WHEN tbp.ddln_dt IS NOT NULL AND DATE(tbp.ddln_dt) < DATE(NOW()) THEN '마감' WHEN DATE(tbp.reg_dt) > DATE(NOW()) THEN '예정' WHEN tbp.ddln_dt IS NULL THEN '-' ELSE '진행중' END AS stts_nm,
ans_cn.bbs_pst_oid AS ansCn_post_no, ans_cn.bbs_oid AS ansCn_board_no, ans_cn.user_oid AS ansCn_user_no, ans_cn.wrtr_nm AS ansCn_writer_nm, ans_cn.bbs_pst_ttl AS ansCn_post_title, ans_cn.bbs_pst_cn AS ansCn_post_content, ans_cn.inq_cnt AS ansCn_view_cnt, ans_cn.up_bbs_pst_oid AS ansCn_parent_post_no, tc1.cd_nm AS ansCn_status, ans_cn.reg_id AS ansCn_reg_user_id, ans_cn.reg_dt AS ansCn_reg_dt, ans_cn.mdfcn_id AS ansCn_upd_user_id, ans_cn.mdfcn_dt AS ansCn_upd_dt, IF(ans_cn.bbs_pst_oid IS NOT NULL, 'Y', 'N') AS ansCn_yn FROM ${schema}.bbs_pst tbp LEFT JOIN ${schema}.bbs_pst ans_cn ON ans_cn.up_bbs_pst_oid = tbp.bbs_pst_oid AND ans_cn.del_yn = 'N' INNER JOIN ${schema}.grp_cd tgc ON tgc.grp_cd = 'QNA_STAT_TYPE' AND tgc.use_yn = 'Y' INNER JOIN ${schema}.cd tc ON tc.grp_cd_oid = tgc.grp_cd_oid AND tc.cd_val = tbp.stts AND tc.use_yn = 'Y' LEFT JOIN ${schema}.cd tc1 ON tc1.grp_cd_oid = tgc.grp_cd_oid AND tc1.cd_val = ans_cn.stts AND tc1.use_yn = 'Y'
tbp.open_yn = 'Y' AND tbp.up_bbs_pst_oid IS NULL
AND tbp.del_yn = #{delYn}
AND tbp.del_yn = 'N'
AND tbp.prvt_pst_yn = #{prvtPstYn}
AND tbp.reg_dt >= #{regStartDt}
AND tbp.reg_dt < DATE_ADD(#{regEndDt}, INTERVAL 1 DAY)
AND tbp.bbs_oid = #{bbsOid}
AND tbp.ctgry = #{ctgry}
AND (
MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE)
MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE)
MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE) OR MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE)
)
GROUP BY tbp.bbs_pst_oid ORDER BY tbp.reg_dt DESC, tbp.bbs_pst_oid DESC

SELECT tbp.bbs_pst_oid, tbp.bbs_oid, tbp.user_oid, tbp.wrtr_nm, tbp.wrtr_pswd, tbp.bbs_pst_ttl, tbp.bbs_pst_cn, tbp.bbs_pst_cn_txt, tbp.ctgry, tbp.ntc_yn, tbp.prvt_pst_yn, tbp.inq_cnt, tbp.like_cnt, tbp.cmnt_cnt, tbp.atch_cnt, IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') AS upend_fix_yn, tbp.bgng_dt, tbp.end_dt, tbp.stts, tbp.ddln_dt, tbp.up_bbs_pst_oid, tbp.reply_lv, tbp.reply_seq, tbp.open_yn, tbp.rcrt_type, tbp.del_yn, tbp.del_dt, tbp.reg_id, tbp.reg_dt, tbp.mdfcn_id, tbp.mdfcn_dt,
/* 상태값 로직 */ CASE WHEN tbp.ddln_dt IS NOT NULL AND DATE(tbp.ddln_dt) < DATE(NOW()) THEN '마감' WHEN DATE(tbp.reg_dt) > DATE(NOW()) THEN '예정' WHEN tbp.ddln_dt IS NULL THEN '-' ELSE '진행중' END AS stts_nm,
/* 썸네일 경로 */ (SELECT CONCAT(tf.strg_file_path, '/', tf.strg_file_nm) FROM ${schema}.file tf WHERE tf.tbl_nm = 'bbs_pst' AND tf.tbl_oid = tbp.bbs_pst_oid AND tf.use_yn = 'Y' AND tf.thmb_yn = 'Y' ORDER BY tf.file_oid LIMIT 1) AS thumbnail_path,
/* 파일 개수 카운트 */ (SELECT COUNT(*) FROM ${schema}.file tf WHERE tf.tbl_nm = 'bbs_pst' AND tf.tbl_oid = tbp.bbs_pst_oid AND tf.use_yn = 'Y' AND tf.thmb_yn = 'N') AS file_cnt
FROM ${schema}.bbs_pst tbp
AND tbp.del_yn = #{delYn}
AND tbp.open_yn = #{openYn}
AND TRIM(tbp.del_yn) = 'N' AND TRIM(tbp.open_yn) = 'Y'
AND tbp.reg_dt >= #{regStartDt}
AND tbp.reg_dt < DATE_ADD(#{regEndDt}, INTERVAL 1 DAY)
AND tbp.bbs_oid = #{bbsOid}
AND tbp.ctgry = #{ctgry}
AND tbp.bbs_pst_oid = #{bbsPstOid}
AND
MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE)
MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE)
(MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE) OR MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE))
ORDER BY IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') DESC, tbp.bbs_pst_oid DESC

SELECT tbp.bbs_pst_oid, tbp.bbs_oid, tbp.user_oid, tbp.wrtr_nm, tbp.wrtr_pswd, tbp.bbs_pst_ttl, tbp.bbs_pst_cn, tbp.bbs_pst_cn_txt, tbp.ctgry, tbp.ntc_yn, tbp.prvt_pst_yn, tbp.inq_cnt, tbp.like_cnt, tbp.cmnt_cnt, tbp.atch_cnt, tbp.upend_fix_yn, tbp.bgng_dt, tbp.end_dt, tbp.stts, tbp.ddln_dt, tbp.up_bbs_pst_oid, tbp.reply_lv, tbp.reply_seq, tbp.open_yn, tbp.rcrt_type, tbp.del_yn, tbp.del_dt, tbp.reg_id, tbp.reg_dt, tbp.mdfcn_id, tbp.mdfcn_dt,
/* 상태값 로직 */ CASE WHEN tbp.ddln_dt IS NOT NULL AND DATE(tbp.ddln_dt) < DATE(NOW()) THEN '마감' WHEN DATE(tbp.reg_dt) > DATE(NOW()) THEN '예정' WHEN tbp.ddln_dt IS NULL THEN '-' ELSE '진행중' END AS stts_nm,
/* 썸네일 경로 */ (SELECT CONCAT(tf.strg_file_path, '/', tf.strg_file_nm) FROM ${schema}.file tf WHERE tf.tbl_nm = 'bbs_pst' AND tf.tbl_oid = tbp.bbs_pst_oid AND tf.use_yn = 'Y' AND tf.thmb_yn = 'Y' ORDER BY tf.file_oid LIMIT 1) AS thumbnail_path,
/* 파일 개수 카운트 */ (SELECT COUNT(*) FROM ${schema}.file tf WHERE tf.tbl_nm = 'bbs_pst' AND tf.tbl_oid = tbp.bbs_pst_oid AND tf.use_yn = 'Y' AND tf.thmb_yn = 'N') AS file_cnt
FROM ${schema}.bbs_pst tbp
tbp.bbs_pst_oid = #{bbsPstOid}
AND tbp.open_yn = #{openYn}
AND tbp.open_yn = 'Y'
AND tbp.del_yn = #{delYn}
AND tbp.del_yn = 'N'
AND tbp.bbs_oid = #{bbsOid}
AND tbp.ctgry = #{ctgry}
AND
MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE)
MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE)
(MATCH(tbp.bbs_pst_ttl) AGAINST(#{keyword} IN BOOLEAN MODE) OR MATCH(tbp.bbs_pst_cn_txt) AGAINST(#{keyword} IN BOOLEAN MODE))
ORDER BY IF(CURDATE() >= tbp.bgng_dt AND (tbp.end_dt IS NULL OR tbp.end_dt >= CURDATE()), 'Y', 'N') DESC, tbp.bbs_pst_oid DESC

SELECT tbp.bbs_pst_oid, tbp.bbs_oid, tbp.user_oid, tbp.wrtr_nm, tbp.wrtr_pswd, tbp.bbs_pst_ttl, tbp.bbs_pst_cn, tbp.bbs_pst_cn_txt, tbp.ans_cn, tbp.ctgry, tbp.ntc_yn, tbp.prvt_pst_yn, tbp.inq_cnt, tbp.like_cnt, tbp.upend_fix_yn, tbp.bgng_dt, tbp.end_dt, tbp.cmnt_cnt, tbp.atch_cnt, tbp.stts, tbp.ddln_dt, tbp.up_bbs_pst_oid, tbp.reply_lv, tbp.reply_seq, tbp.open_yn, tbp.rcrt_type, tbp.del_yn, tbp.del_dt, tbp.reg_id, tbp.reg_dt, tbp.mdfcn_id, tbp.mdfcn_dt, tbp.kwrd FROM ${schema}.bbs_pst tbp
AND tbp.del_yn = #{delYn}
AND tbp.del_yn = 'N'
AND tbp.bbs_oid = #{bbsOid}
AND tbp.bbs_pst_oid = #{bbsPstOid}
ORDER BY tbp.bbs_pst_oid DESC

SELECT -- 질문(원글) 정보 q.bbs_pst_oid, q.bbs_oid, q.user_oid, q.wrtr_nm, q.wrtr_pswd, q.bbs_pst_ttl, q.bbs_pst_cn, q.bbs_pst_cn_txt, q.ctgry, q.ntc_yn, q.prvt_pst_yn, q.upend_fix_yn, q.bgng_dt, q.end_dt, q.inq_cnt, q.like_cnt, q.cmnt_cnt, q.atch_cnt, q.stts, q.ddln_dt, q.up_bbs_pst_oid, q.reply_lv, q.reply_seq, q.del_yn, q.del_dt, q.reg_id, q.reg_dt, q.mdfcn_id, q.mdfcn_dt,
-- 답변 정보 a.bbs_pst_oid AS answer_post_no, a.bbs_oid AS answer_board_no, a.user_oid AS answer_user_no, a.wrtr_nm AS answer_writer_nm, a.bbs_pst_ttl AS answer_post_title, a.bbs_pst_cn AS answer_post_content, a.inq_cnt AS answer_view_cnt, a.up_bbs_pst_oid AS answer_parent_post_no, a.reg_id AS answer_reg_user_id, a.reg_dt AS answer_reg_dt, a.mdfcn_id AS answer_upd_user_id, a.mdfcn_dt AS answer_upd_dt, IF(a.bbs_pst_oid IS NOT NULL, 'Y', 'N') AS answer_yn,
-- 답변 첨부파일 af.file_oid AS answer_attach_no, af.tbl_oid AS answer_attach_post_no, af.strg_file_nm AS answer_file_name, af.orgnl_file_nm AS answer_origin_file_name, af.strg_file_path AS answer_file_path, af.strg_file_cpct AS answer_file_size, af.file_type_nm AS answer_file_ext, af.strg_sml_file_path AS answer_thumbnail_path, af.thmb_yn AS answer_thumbnail_yn, 0 AS answer_image_width, 0 AS answer_image_height, af.dwnld_cnt AS answer_download_cnt, af.atch_file_seq AS answer_attach_order, af.use_yn AS answer_use_yn, af.reg_id AS answer_attach_reg_user_id, af.reg_dt AS answer_attach_reg_dt FROM ${schema}.bbs_pst q LEFT JOIN ${schema}.bbs_pst a ON a.up_bbs_pst_oid = q.bbs_pst_oid AND a.del_yn = 'N' LEFT JOIN ${schema}.file af ON a.bbs_pst_oid = af.tbl_oid AND af.tbl_nm = 'bbs_pst' AND af.file_type = 'ATTACHMENT' AND af.use_yn = 'Y'
q.up_bbs_pst_oid IS NULL
AND q.del_yn = #{delYn}
AND q.del_yn = 'N'
AND q.bbs_oid = #{bbsOid}
AND q.bbs_pst_oid = #{bbsPstOid}
ORDER BY q.bbs_pst_oid DESC, a.bbs_pst_oid ASC

